import { createAuth } from '@auth/lib/better-auth';
import type { AppContext } from '@auth/lib/context';
import { createMiddleware } from 'hono/factory';

export const authInstanceMiddleware = createMiddleware<AppContext>(
  async (c, next) => {
    const auth = createAuth(c.env);
    c.set('betterAuth', auth);
    await next();
  },
);

export const authContextMiddleware = createMiddleware<AppContext>(
  async (c, next) => {
    const auth = c.var.betterAuth;
    const session = await auth.api.getSession({
      headers: c.req.raw.headers,
    });

    if (!session?.session) {
      c.set('user', null);
      c.set('session', null);
      return next();
    }

    // Set both the user and session objects from the session response
    c.set('user', session.user);
    c.set('session', session.session);

    await next();
  },
);

import { Hono } from "hono";
import { describeRoute, resolver } from "hono-openapi";
import * as v from "valibot";
import getIdToken from "./controllers/get-id-token";

const oauth = new Hono<{ Variables: { userId: string } }>().get(
  "/id-token",
  describeRoute({
    operationId: "getOAuthIdToken",
    tags: ["Authentication"],
    description: "Get the id_token for the current user's custom OAuth account",
    responses: {
      200: {
        description: "The id_token if available",
        content: {
          "application/json": {
            schema: resolver(v.object({ idToken: v.nullable(v.string()) })),
          },
        },
      },
    },
  }),
  async (c) => {
    const userId = c.get("userId");
    const result = await getIdToken(userId);
    return c.json(result);
  },
);

export default oauth;

import * as esbuild from 'esbuild'
import * as fs from 'node:fs'
import * as os from 'os'
import * as path from 'path'

async function main() {
  const tempDir = os.tmpdir()
  const tempFilePath = path.join(tempDir, 'bundle.tmp.js')

  try {
    await esbuild.build({
      entryPoints: ['dist/index.js'],
      bundle: true,
      minify: true,
      format: 'esm' as esbuild.Format,
      target: 'es2022',
      outfile: tempFilePath,
    })

    const bundleSize = fs.statSync(tempFilePath).size
    const metrics = []

    metrics.push({
      key: 'bundle-size-b',
      name: 'Bundle Size (B)',
      value: bundleSize,
      unit: 'B',
    })

    metrics.push({
      key: 'bundle-size-kb',
      name: 'Bundle Size (KB)',
      value: parseFloat((bundleSize / 1024).toFixed(2)),
      unit: 'K',
    })

    const benchmark = {
      key: 'bundle-size-check',
      name: 'Bundle size check',
      metrics,
    }
    console.log(JSON.stringify(benchmark, null, 2))
  } catch (error) {
    console.error('Build failed:', error)
  } finally {
    if (fs.existsSync(tempFilePath)) {
      fs.unlinkSync(tempFilePath)
    }
  }
}

main()

import { Hono, Context } from "hono";
import { getUser } from '../lib/auth';
import { getCookie } from "hono/cookie";


const restrictToLoggedinUserOnly = async (c: Context, next: Function) => {
  const userUid = getCookie(c, 'sessionId');

  if (!userUid) {
    return c.json({ message: "Unauthorized: No active session found" }, 401);
  }

  const user = await getUser(userUid);

  if (!user) {
    return c.json({ message: "Unauthorized: Session invalid or expired" }, 401);
  }

  c.set('user', user);
  await next();
}

const checkAuth = async (c: Context, next: Function) => {
  const userUid = getCookie(c, 'sessionId');

  if (!userUid) {
    return c.json({ message: "Unauthorized: No active session found" }, 401);
  }

  const user = await getUser(userUid); // Ensure getUser is async or handle accordingly

  c.set('user', user);
  await next();
}

export { restrictToLoggedinUserOnly, checkAuth };

