import { appConfig } from 'shared';
import type { AuthContext } from '#/core/context';
import type { OperationResult } from '#/core/operation-result';
import { tenantRead } from '#/db/tenant-context';
import { findAttachmentByKey } from '#/modules/attachment/attachment-queries';
import { getSignedUrlFromKey } from '#/modules/attachment/helpers/signed-url';
import { checkPermission } from '#/permissions';

export async function getPresignedUrlOp(ctx: AuthContext, key: string): Promise<OperationResult<string>> {
  const attachment = await tenantRead(ctx, async (readCtx) => {
    return findAttachmentByKey(readCtx, { key });
  });

  const bucketName = attachment?.bucketName ?? appConfig.s3.privateBucket;

  if (attachment) {
    const isSystemAdmin = ctx.var.isSystemAdmin;
    const memberships = ctx.var.memberships;

    const { isAllowed } = checkPermission(memberships, 'read', attachment);

    if (!isSystemAdmin && !isAllowed) {
      return { success: false, error: 'forbidden', status: 403 };
    }
  }

  const url = await getSignedUrlFromKey(key, { bucketName, isPublic: false });

  return { success: true, data: url };
}

import type { AuthContext } from '#/core/context';
import { AppError } from '#/core/error';
import { findDomainByName, findTenantExists, insertDomain } from '#/modules/domains/domains-queries';
import { logEvent } from '#/utils/logger';

export async function createDomainOp(ctx: AuthContext, domain: string) {
  const tenantId = ctx.var.tenantId;

  // Check tenant exists
  const tenant = await findTenantExists(ctx);
  if (!tenant) {
    throw new AppError(404, 'not_found', 'warn', { meta: { resource: 'tenant' } });
  }

  // Check domain not already claimed
  const existing = await findDomainByName(ctx, { domain });
  if (existing) {
    throw new AppError(409, 'invalid_request', 'warn', { meta: { reason: 'Domain already claimed' } });
  }

  const created = await insertDomain(ctx, { domain });

  logEvent(ctx, 'info', 'Domain added', { tenantId, domain });

  return created;
}

import type { z } from '@hono/zod-openapi';
import type { EnabledOAuthProvider } from 'shared';
import { appConfig } from 'shared';
import type { AuthContext } from '#/core/context';
import { getAuthInfo } from '#/modules/me/helpers/get-user-info';
import type { sessionSchema } from '#/modules/me/me-schema';

interface GetMyAuthOpts {
  sessions: z.infer<typeof sessionSchema>[];
}

export async function getMyAuthOp(ctx: AuthContext, { sessions }: GetMyAuthOpts) {
  const user = ctx.var.user;
  const db = ctx.var.db;

  const authInfo = await getAuthInfo({ var: { db } }, { userId: user.id });

  const { oauth, ...restInfo } = authInfo;
  const enabledOAuth = oauth
    .map(({ provider }) => provider)
    .filter((provider): provider is EnabledOAuthProvider =>
      appConfig.enabledOAuthProviders.includes(provider as EnabledOAuthProvider),
    );

  return { ...restInfo, enabledOAuth, sessions };
}

