import { getTenantsList } from '#/modules/tenants/tenants-queries';
import type { tenantListQuerySchema } from '#/modules/tenants/tenants-schema';
import { prepareStringForILikeFilter } from '#/utils/sql';

type GetTenantsInput = z.infer<typeof tenantListQuerySchema>;

export async function getTenantsOp(ctx: AuthContext, input: GetTenantsInput) {
  const { q, status, limit, offset, sort, order } = input;

  // Build where conditions
  const conditions: SQL[] = [];
  if (q) {
    const searchQuery = prepareStringForILikeFilter(q);
    conditions.push(ilike(tenantsTable.name, searchQuery));
  }
  if (status) {
    conditions.push(eq(tenantsTable.status, status));
  }

  const { items, total } = await getTenantsList(ctx, { filters: conditions, sort, order, limit, offset });

  return { items, total };
}

import { createMiddleware } from 'hono/factory';
import type { AppBindings } from '@/lib/context';
import { ScrapeService } from '@/services/scrape/scrape.service';

// Request-scoped service factory to prevent resource leaks in workerd
// This ensures proper IoContext lifecycle management while maintaining performance
// Only creates scrapeService (used by all endpoints) - other services created on-demand
function createRequestScopedServices() {
  const services = {
    scrapeService: new ScrapeService(),
  };

  return services;
}

export const servicesAppMiddleware = createMiddleware<AppBindings>(
  async (c, next) => {
    // check if the path contains 'read' or 'links'
    if (!(c.req.path.includes('read') || c.req.path.includes('links'))) {
      return next();
    }

    // Create services per request to respect IoContext boundaries
    // This prevents resource leaks in production workerd
    const services = createRequestScopedServices();

    c.set('scrapeService', services.scrapeService);

    return next();
  },
);

